INSERT INTO proverbs (id, spanish, arabic, english, category, note, image, curator, date, bookmarked) VALUES
('1', 'A quien madruga, Dios le ayuda.', 'من جد وجد', 'The early bird catches the worm.', 'Wisdom', 'Un refrán sobre la diligencia y la acción temprana que conduce al éxito.', 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=400', 'A. Al-Fayed', '12th Oct, 2023', 0),
('2', 'Más vale pájaro en mano que ciento volando.', 'عصفور في اليد خير من عشرة على الشجرة', 'A bird in the hand is worth two in the bush.', 'Prudence', 'Este refrán advises not to risk a sure gain for a potentially greater but uncertain one.', 'https://images.unsplash.com/photo-1444464666168-49d633b86797?w=400', 'A. Al-Fayed', '12th Oct, 2023', 0),
('3', 'El tiempo es oro.', 'الوقت من ذهب', 'Time is money.', 'Time', 'A universal proverb emphasizing the value of time.', 'https://images.unsplash.com/photo-1501139083538-0139583c060f?w=400', 'A. Al-Fayed', '12th Oct, 2023', 0),
('4', 'Ojos que no ven, corazón que no siente.', 'بعيد عن العين بعيد عن القلب', 'Out of sight, out of mind.', 'Nature', 'A proverb about emotional distance and awareness.', 'https://images.unsplash.com/photo-1518837695005-2083093ee35b?w=400', 'A. Al-Fayed', '12th Oct, 2023', 0),
('5', 'No hay mal que por bien no venga.', 'لكل شيء حل', 'Every cloud has a silver lining.', 'Optimism', 'Every difficult situation has some benefit or positive aspect.', 'https://images.unsplash.com/photo-1534088568595-a066f410bcda?w=400', 'A. Al-Fayed', '13th Oct, 2023', 0),
('6', 'Agua que no has de beber, déjala correr.', 'دع ما لا يعنيك', 'Let sleeping dogs lie.', 'Wisdom', 'Advice to avoid stirring up trouble unnecessarily.', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400', 'A. Al-Fayed', '13th Oct, 2023', 0),
('7', 'Aprende a caminar antes de correr.', 'تعلم المشي قبل الركض', 'Learn to walk before you run.', 'Patience', 'One must master basics before attempting advanced skills.', 'https://images.unsplash.com/photo-1476480862126-209bfaa8edc8?w=400', 'A. Al-Fayed', '14th Oct, 2023', 0),
('8', 'Barriga vacía, corazón triste.', 'الجوع يفعل العجائب', 'A hungry man is an angry man.', 'Life', 'Hunger affects mood and behavior.', 'https://images.unsplash.com/photo-1493770348161-369560ae357d?w=400', 'A. Al-Fayed', '14th Oct, 2023', 0),
('9', 'Cada quien es hijo de sus obras.', 'الإنسان صنع يديه', 'You are the architect of your own destiny.', 'Responsibility', 'Your actions shape your future.', 'https://images.unsplash.com/photo-1503424886307-b090341d25d1?w=400', 'A. Al-Fayed', '15th Oct, 2023', 0),
('10', 'De tal palo, tal astilla.', 'مثل الأب مثل الابن', 'Like father, like son.', 'Family', 'Children often resemble their parents.', 'https://images.unsplash.com/photo-1511895426328-dc8714191300?w=400', 'A. Al-Fayed', '15th Oct, 2023', 0),
('11', 'El que busca, encuentra.', 'من يبحث يجد', 'Seek and you shall find.', 'Persistence', 'Those who search will eventually find what they are looking for.', 'https://images.unsplash.com/photo-1516979187457-637abb4f9353?w=400', 'A. Al-Fayed', '16th Oct, 2023', 0),
('12', 'En el país de los ciegos, el tuerto es el rey.', 'في بلد العمى حِمارُكَ مَلَك', 'In the land of the blind, the one-eyed man is king.', 'Comparison', 'Inferior quality seems excellent when compared to even worse.', 'https://images.unsplash.com/photo-1456421385069-d3f46f5f73d4?w=400', 'A. Al-Fayed', '16th Oct, 2023', 0),
('13', 'Gato escaldado del agua fría huye.', 'مَنْ أُوذِيَ مِنْ كَلْبٍ ظَلَّ يَخافُ مِنْ شِباهِهِ', 'Once bitten, twice shy.', 'Experience', 'A bad experience makes you more cautious.', 'https://images.unsplash.com/photo-1574158622682-e40e69881006?w=400', 'A. Al-Fayed', '17th Oct, 2023', 0),
('14', 'Haz bien y no mires a quien.', 'افعل الخير ولا تنتظر الشكر', 'Do good without expecting anything in return.', 'Generosity', 'Help others without expecting gratitude.', 'https://images.unsplash.com/photo-1531206715517-5c0ba140b2b8?w=400', 'A. Al-Fayed', '17th Oct, 2023', 0),
('15', 'La curiosidad es mala.', 'الفضول شر', 'Curiosity killed the cat.', 'Caution', 'Being too inquisitive can get you into trouble.', 'https://images.unsplash.com/photo-1518020382113-a7e8fc38eac9?w=400', 'A. Al-Fayed', '18th Oct, 2023', 0),
('16', 'Llover sobre mojado.', 'المصائب لا تأتي فرادى', 'When it rains, it pours.', 'Misfortune', 'Problems often come all at once.', 'https://images.unsplash.com/photo-1515694346937-94d85e41e6f0?w=400', 'A. Al-Fayed', '18th Oct, 2023', 0),
('17', 'Más deprisa, menos prisa.', 'العجلة من الشيطان', 'More haste, less speed.', 'Patience', 'Rushing often leads to mistakes and delays.', 'https://images.unsplash.com/photo-1509281373149-e957c6296406?w=400', 'A. Al-Fayed', '19th Oct, 2023', 0),
('18', 'Nadie es profeta en su tierra.', 'النبي في بلده', 'A prophet is not honored in his own country.', 'Recognition', 'People often fail to appreciate those close to them.', 'https://images.unsplash.com/photo-1522202176988-66273c2fd55f?w=400', 'A. Al-Fayed', '19th Oct, 2023', 0),
('19', 'Nunca es tarde para aprender.', 'ما لا يُدرك كله لا يُترك جله', 'You are never too old to learn.', 'Education', 'Learning has no age limits.', 'https://images.unsplash.com/photo-1456513080510-7bf3a84b82f8?w=400', 'A. Al-Fayed', '20th Oct, 2023', 0),
('20', 'Obras son amores, que no buenas razones.', 'الأفعال أبلغ من الأقوال', 'Actions speak louder than words.', 'Truth', 'What you do matters more than what you say.', 'https://images.unsplash.com/photo-1524178232363-1fb2b075b655?w=400', 'A. Al-Fayed', '20th Oct, 2023', 0),
('21', 'Perro que ladra no muerde.', 'الكلب الذي ينبح لا يعض', 'Barking dogs seldom bite.', 'Wisdom', 'Those who threaten often do not act.', 'https://images.unsplash.com/photo-1587300003388-59208cc962cb?w=400', 'A. Al-Fayed', '21st Oct, 2023', 0),
('22', 'Quien llama a tu puerta, ábrela.', 'افتح الباب لمن يطرق', 'When opportunity knocks, open the door.', 'Opportunity', 'Take advantage of opportunities when they arise.', 'https://images.unsplash.com/photo-1481349518771-20055b2a7b24?w=400', 'A. Al-Fayed', '21st Oct, 2023', 0),
('23', 'Ser como el perro del hortelano.', 'كلب البستان', 'Like the gardener''s dog - neither eats nor lets others eat.', 'Behavior', 'Someone who neither enjoys something nor lets others enjoy it.', 'https://images.unsplash.com/photo-1548199973-03cce0bbc87b?w=400', 'A. Al-Fayed', '22nd Oct, 2023', 0),
('24', 'Tan cierto como que dos y dos son cuatro.', 'أثبت من ذلك', 'As sure as eggs is eggs.', 'Certainty', 'Something absolutely undeniable.', 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?w=400', 'A. Al-Fayed', '22nd Oct, 2023', 0),
('25', 'Todos los caminos llevan a Roma.', 'كل الطرق تؤدي إلى روما', 'All roads lead to Rome.', 'Outcome', 'There are many ways to achieve the same goal.', 'https://images.unsplash.com/photo-1529260830199-42c42dda5f30?w=400', 'A. Al-Fayed', '23rd Oct, 2023', 0),
('26', 'Un clavo saca otro clavo.', 'مسمار يسحب مسمار', 'A nail drives out a nail.', 'Solution', 'One problem can be solved by introducing another.', 'https://images.unsplash.com/photo-1504328345606-18bbc8c9d7d1?w=400', 'A. Al-Fayed', '23rd Oct, 2023', 0),
('27', 'Vivir para ver.', 'عش ترى', 'You live and learn.', 'Experience', 'Life teaches us new things every day.', 'https://images.unsplash.com/photo-1499209974431-9dddcece7f88?w=400', 'A. Al-Fayed', '24th Oct, 2023', 0),
('28', 'Zapatero, a tus zapatos.', 'حذّار أحذيته', 'Stick to your last.', 'Expertise', 'Focus on what you know best.', 'https://images.unsplash.com/photo-1527864550417-7fd91fc51a46?w=400', 'A. Al-Fayed', '24th Oct, 2023', 0),
('29', 'Al mal tiempo, buena cara.', 'وجهاً طلقاً', 'Keep a stiff upper lip.', 'Attitude', 'Stay positive despite difficulties.', 'https://images.unsplash.com/photo-1529129082029-7603431b5225?w=400', 'A. Al-Fayed', '25th Oct, 2023', 0),
('30', 'Antes de actuar, piensa.', 'فكر قبل أن تتصرف', 'Think before you act.', 'Wisdom', 'Consider consequences before taking action.', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400', 'A. Al-Fayed', '25th Oct, 2023', 0);
